from gh_hj h
left join system_dept d on h.dept_id = d.id

    AND h.dept_id = #{query.deptId}
    AND h.djxh = #{query.djxh}
    AND h.shxydm = #{query.shxydm}
    AND h.nsrmc LIKE CONCAT('%', #{query.nsrmc}, '%')
    AND h.hyghbz = #{query.hyghbz}
    AND h.nsrzt_dm = #{query.nsrztDm}
    AND h.ghlb_dm = #{query.ghlbDm}
