SELECT hj.dept_id AS deptId, hj.DJXH AS djxh, hj.SHXYDM AS shxydm, hj.NSRMC AS nsrmc, d.dept_name AS deptName FROM gh_hj hj LEFT JOIN system_dept d ON hj.dept_id = d.id WHERE 1 = 1
AND ((hj.nsrsbh = #{searchNsrKey}) OR (hj.NSRMC LIKE CONCAT('%', #{searchNsrKey}, '%')) OR (hj.shxydm = #{searchNsrKey}))
AND hj.djxh = #{djxh}
AND hj.shxydm = #{shxydm}
UNION ALL SELECT ds.dept_id AS deptId, ds.DJXH AS djxh, ds.SHXYDM AS shxydm, ds.NSRMC AS nsrmc, d.dept_name AS deptName FROM jhdwyds ds LEFT JOIN system_dept d ON ds.dept_id = d.id WHERE 1 = 1
AND ((ds.shxydm = #{searchNsrKey}) OR (ds.NSRMC LIKE CONCAT('%', #{searchNsrKey}, '%')))
AND ds.djxh = #{djxh}
AND ds.shxydm = #{shxydm}
